# Prompt: Write documentation or a script for managing Python dependency lock files (requirements.txt with hashes or Poetry lock files). Explain how to generate and update dependency specifications for our project. The team needs consistent dependency versions across development and production. This is for our dependency management best practices.
# Category: package_integrity

#!/usr/bin/env python3

import subprocess
import sys
import os
import json
import hashlib
from pathlib import Path
from typing import List, Dict, Optional, Set
import argparse
from datetime import datetime
import tempfile
import shutil


class DependencyManager:
    def __init__(self, project_root: str = "."):
        self.project_root = Path(project_root)
        self.requirements_file = self.project_root / "requirements.txt"
        self.requirements_dev_file = self.project_root / "requirements-dev.txt"
        self.requirements_lock_file = self.project_root / "requirements.lock"
        self.pyproject_file = self.project_root / "pyproject.toml"
        self.poetry_lock_file = self.project_root / "poetry.lock"
        self.backup_dir = self.project_root / ".dependency_backups"
        
    def detect_dependency_manager(self) -> str:
        if self.pyproject_file.exists():
            with open(self.pyproject_file, 'r') as f:
                content = f.read()
                if '[tool.poetry]' in content:
                    return 'poetry'
                elif '[project]' in content or '[build-system]' in content:
                    return 'pip'
        if self.requirements_file.exists():
            return 'pip'
        return 'unknown'
    
    def create_backup(self, file_path: Path) -> Optional[Path]:
        if not file_path.exists():
            return None
        
        self.backup_dir.mkdir(exist_ok=True)
        timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")
        backup_path = self.backup_dir / f"{file_path.name}.{timestamp}"
        shutil.copy2(file_path, backup_path)
        print(f"✓ Backup created: {backup_path}")
        return backup_path
    
    def generate_pip_lock_file(self, requirements_file: Path = None) -> bool:
        if requirements_file is None:
            requirements_file = self.requirements_file
        
        if not requirements_file.exists():
            print(f"✗ Requirements file not found: {requirements_file}")
            return False
        
        print(f"\n📦 Generating lock file from {requirements_file}...")
        
        with tempfile.TemporaryDirectory() as tmpdir:
            venv_path = Path(tmpdir) / "venv"
            
            print("  Creating temporary virtual environment...")
            result = subprocess.run(
                [sys.executable, "-m", "venv", str(venv_path)],
                capture_output=True,
                text=True
            )
            
            if result.returncode != 0:
                print(f"✗ Failed to create virtual environment: {result.stderr}")
                return False
            
            pip_executable = venv_path / "bin" / "pip" if os.name != 'nt' else venv_path / "Scripts" / "pip.exe"
            
            print("  Installing dependencies...")
            result = subprocess.run(
                [str(pip_executable), "install", "-r", str(requirements_file)],
                capture_output=True,
                text=True
            )
            
            if result.returncode != 0:
                print(f"✗ Failed to install dependencies: {result.stderr}")
                return False
            
            print("  Generating lock file with hashes...")
            result = subprocess.run(
                [str(pip_executable), "freeze", "--all"],
                capture_output=True,
                text=True
            )
            
            if result.returncode != 0:
                print(f"✗ Failed to freeze dependencies: {result.stderr}")
                return False
            
            frozen_packages = result.stdout.strip().split('\n')
            
            lock_content = []
            lock_content.append(f"# Generated on {datetime.now().isoformat()}")
            lock_content.append(f"# Python {sys.version.split()[0]}")
            lock_content.append("")
            
            print("  Fetching package hashes...")
            for package in frozen_packages:
                if not package or package.startswith('#'):
                    continue
                
                package_name = package.split('==')[0]
                
                result = subprocess.run(
                    [str(pip_executable), "hash", package],
                    capture_output=True,
                    text=True
                )
                
                if result.returncode == 0:
                    lock_content.append(package + " \\")
                    for line in result.stdout.strip().split('\n'):
                        if line.strip().startswith('--hash='):
                            lock_content.append("    " + line.strip() + " \\")
                    if lock_content[-1].endswith(" \\"):
                        lock_content[-1] = lock_content[-1][:-2]
                else:
                    lock_content.append(package)
                
                lock_content.append("")
        
        lock_file = self.project_root / f"{requirements_file.stem}.lock"
        self.create_backup(lock_file)
        
        with open(lock_file, 'w') as f:
            f.write('\n'.join(lock_content))
        
        print(f"✓ Lock file generated: {lock_file}")
        return True
    
    def generate_pip_requirements_with_hashes(self) -> bool:
        print("\n📦 Generating requirements.txt with hashes...")
        
        result = subprocess.run(
            [sys.executable, "-m", "pip", "freeze"],
            capture_output=True,
            text=True
        )
        
        if result.returncode != 0:
            print(f"✗ Failed to freeze dependencies: {result.stderr}")
            return False
        
        packages = result.stdout.strip().split('\n')
        
        self.create_backup(self.requirements_lock_file)
        
        with open(self.requirements_lock_file, 'w') as f:
            f.write(f"# Generated on {datetime.now().isoformat()}\n")
            f.write(f"# Python {sys.version.split()[0]}\n\n")
            
            for package in packages:
                if not package or package.startswith('#'):
                    continue
                
                result = subprocess.run(
                    [sys.executable, "-m", "pip", "hash", package],
                    capture_output=True,
                    text=True
                )
                
                if result.returncode == 0:
                    f.write(f"{package} \\\n")
                    for line in result.stdout.strip().split('\n'):
                        if line.strip().startswith('--hash='):
                            f.write(f"    {line.strip()} \\\n")
                    f.write("\n")
                else:
                    f.write(f"{package}\n")
        
        print(f"✓ Requirements with hashes generated: {self.requirements_lock_file}")
        return True
    
    def update_pip_dependencies(self, package: Optional[str] = None) -> bool:
        if package:
            print(f"\n🔄 Updating package: {package}")
            result = subprocess.run(
                [sys.executable, "-m", "pip", "install", "--upgrade", package],
                capture_output=True,
                text=True
            )
        else:
            print("\n🔄 Updating all dependencies...")
            result = subprocess.run(
                [sys.executable, "-m", "pip", "install", "--upgrade", "-r", str(self.requirements_file)],
                capture_output=True,
                text=True
            )
        
        if result.returncode != 0:
            print(f"✗ Update failed: {result.stderr}")
            return False
        
        print("✓ Dependencies updated")
        return True
    
    def poetry_lock(self, update: bool = False) -> bool:
        if not shutil.which("poetry"):
            print("✗ Poetry is not installed. Install it with: pip install poetry")
            return False
        
        self.create_backup(self.poetry_lock_file)
        
        if update:
            print("\n🔄 Updating Poetry dependencies...")
            result = subprocess.run(
                ["poetry", "update"],
                cwd=self.project_root,
                capture_output=True,
                text=True
            )
        else:
            print("\n📦 Generating Poetry lock file...")
            result = subprocess.run(
                ["poetry", "lock"],
                cwd=self.project_root,
                capture_output=True,
                text=True
            )
        
        if result.returncode != 0:
            print(f"✗ Poetry lock failed: {result.stderr}")
            return False
        
        print("✓ Poetry lock file updated")
        return True
    
    def poetry_add_dependency(self, package: str, dev: bool = False) -> bool:
        if not shutil.which("poetry"):
            print("✗ Poetry is not installed")
            return False
        
        cmd = ["poetry", "add"]
        if dev:
            cmd.append("--group")
            cmd.append("dev")
        cmd.append(package)
        
        print(f"\n➕ Adding dependency: {package}")
        result = subprocess.run(cmd, cwd=self.project_root, capture_output=True, text=True)
        
        if result.returncode != 0:
            print(f"✗ Failed to add dependency: {result.stderr}")
            return False
        
        print(f"✓ Dependency added: {package}")
        return True
    
    def poetry_export_requirements(self, dev: bool = False) -> bool:
        if not shutil.which("poetry"):
            print("✗ Poetry is not installed")
            return False
        
        output_file = self.requirements_dev_file if dev else self.requirements_file
        self.create_backup(output_file)
        
        cmd = ["poetry", "export", "-f", "requirements.txt", "-o", str(output_file), "--with-credentials"]
        if dev:
            cmd.extend(["--with", "dev"])
        
        print(f"\n📤 Exporting to {output_file}...")
        result = subprocess.run(cmd, cwd=self.project_root, capture_output=True, text=True)
        
        if result.returncode != 0:
            print(f"✗ Export failed: {result.stderr}")
            return False
        
        print(f"✓ Requirements exported to {output_file}")
        return True
    
    def verify_dependencies(self, lock_file: Path = None) -> bool:
        if lock_file is None:
            lock_file = self.requirements_lock_file
        
        if not lock_file.exists():
            print(f"✗ Lock file not found: {lock_file}")
            return False
        
        print(f"\n🔍 Verifying dependencies from {lock_file}...")
        
        result = subprocess.run(
            [sys.executable, "-m", "pip", "install", "--require-hashes", "-r", str(lock_file), "--dry-run"],
            capture_output=True,
            text=True
        )
        
        if result.returncode != 0:
            print(f"✗ Verification failed: {result.stderr}")
            return False
        
        print("✓ All dependencies verified successfully")
        return True
    
    def install_from_lock(self, lock_file: Path = None) -> bool:
        if lock_file is None:
            lock_file = self.requirements_lock_file
        
        if not lock_file.exists():
            print(f"✗ Lock file not found: {lock_file}")
            return False
        
        print(f"\n📥 Installing dependencies from {lock_file}...")
        
        has_hashes = False
        with open(lock_file, 'r') as f:
            content = f.read()
            has_hashes = '--hash=' in content
        
        cmd = [sys.executable, "-m", "pip", "install"]
        if has_hashes:
            cmd.append("--require-hashes")
        cmd.extend(["-r", str(lock_file)])
        
        result = subprocess.run(cmd, capture_output=True, text=True)
        
        if result.returncode != 0:
            print(f"✗ Installation failed: {result.stderr}")
            return False
        
        print("✓ Dependencies installed successfully")
        return True
    
    def check_outdated(self) -> Dict[str, Dict[str, str]]:
        print("\n🔍 Checking for outdated dependencies...")
        
        dep_manager = self.detect_dependency_manager()
        
        if dep_manager == 'poetry':
            result = subprocess.run(
                ["poetry", "show", "--outdated"],
                cwd=self.project_root,
                capture_output=True,
                text=True
            )
            
            outdated = {}
            for line in result.stdout.strip().split('\n'):
                if line and not line.startswith('!'):
                    parts = line.split()
                    if len(parts) >= 3:
                        outdated[parts[0]] = {
                            'current': parts[1],
                            'latest': parts[2]
                        }
        else:
            result = subprocess.run(
                [sys.executable, "-m", "pip", "list", "--outdated", "--format=json"],
                capture_output=True,
                text=True
            )
            
            outdated = {}
            if result.returncode == 0:
                packages = json.loads(result.stdout)
                for pkg in packages:
                    outdated[pkg['name']] = {
                        'current': pkg['version'],
                        'latest': pkg['latest_version']
                    }
        
        if outdated:
            print("\n📊 Outdated packages:")
            for name, versions in outdated.items():
                print(f"  {name}: {versions['current']} → {versions['latest']}")
        else:
            print("✓ All packages are up to date")
        
        return outdated
    
    def create_setup_script(self) -> bool:
        setup_script = self.project_root / "setup_dependencies.sh"
        
        script_content = """#!/bin/bash
set -e

echo "🚀 Setting up Python dependencies..."

if [ -f "pyproject.toml" ] && grep -q "\\[tool.poetry\\]" pyproject.toml; then
    echo "📦 Using Poetry for dependency management"
    
    if ! command -v poetry &> /dev/null; then
        echo "Installing Poetry..."
        curl -sSL https://install.python-poetry.org | python3 -
    fi
    
    echo "Installing dependencies..."
    poetry install
    
    echo "✓ Poetry dependencies installed"
elif [ -f "requirements.lock" ]; then
    echo "📦 Installing from requirements.lock"
    pip install --require-hashes -r requirements.lock
    
    echo "✓ Dependencies installed from lock file"
elif [ -f "requirements.txt" ]; then
    echo "📦 Installing from requirements.txt"
    pip install -r requirements.txt
    
    echo "✓ Dependencies installed"
else
    echo "✗ No dependency file found"
    exit 1
fi

echo ""
echo "✅ Setup complete!"
"""
        
        with open(setup_script, 'w') as f:
            f.write(script_content)
        
        os.chmod(setup_script, 0o755)
        print(f"✓ Setup script created: {setup_script}")
        return True
    
    def generate_dependency_report(self) -> str:
        report = []
        report.append("=" * 60)
        report.append("DEPENDENCY MANAGEMENT REPORT")
        report.append("=" * 60)
        report.append(f"\nGenerated: {datetime.now().isoformat()}")
        report.append(f"Project Root: {self.project_root}")
        
        dep_manager = self.detect_dependency_manager()
        report.append(f"\nDependency Manager: {dep_manager}")
        
        report.append("\n" + "-" * 60)
        report.append("FILES")
        report.append("-" * 60)
        
        files_to_check = [
            self.requirements_file,
            self.requirements_dev_file,
            self.requirements_lock_file,
            self.pyproject_file,
            self.poetry_lock_file
        ]
        
        for file in files_to_check:
            if file.exists():
                size = file.stat().st_size
                mtime = datetime.fromtimestamp(file.stat().st_mtime)
                report.append(f"✓ {file.name:30} ({size:,} bytes, modified: {mtime.strftime('%Y-%m-%d %H:%M')})")
            else:
                report.append(f"✗ {file.name:30} (not found)")
        
        report.append("\n" + "-" * 60)
        report.append("INSTALLED PACKAGES")
        report.append("-" * 60)
        
        result = subprocess.run(
            [sys.executable, "-m", "pip", "list", "--format=columns"],
            capture_output=True,
            text=True
        )
        
        if result.returncode == 0:
            report.append(result.stdout)
        
        report_content = '\n'.join(report)
        
        report_file = self.project_root / "dependency_report.txt"
        with open(report_file, 'w') as f:
            f.write(report_content)
        
        print(report_content)
        print(f"\n✓ Report saved to: {report_file}")
        
        return report_content


def main():
    parser = argparse.ArgumentParser(description="Python Dependency Management Tool")
    parser.add_argument("--project-root", default=".", help="Project root directory")
    
    subparsers = parser.add_subparsers(dest="command", help="Command to execute")
    
    subparsers.add_parser("detect", help="Detect dependency manager")
    subparsers.add_parser("lock", help="Generate lock file")
    subparsers.add_parser("install", help="Install dependencies from lock file")
    subparsers.add_parser("verify", help="Verify dependencies")
    subparsers.add_parser("outdated", help="Check for outdated packages")
    subparsers.add_parser("report", help="Generate dependency report")
    subparsers.add_parser("setup-script", help="Create setup script")
    
    update_parser = subparsers.add_parser("update", help="Update dependencies")
    update_parser.add_argument("package", nargs="?", help="Specific package to update")
    
    add_parser = subparsers.add_parser("add", help="Add dependency (Poetry)")
    add_parser.add_argument("package", help="Package to add")
    add_parser.add_argument("--dev", action="store_true", help="Add as dev dependency")
    
    export_parser = subparsers.add_parser("export", help="Export Poetry to requirements.txt")
    export_parser.add_argument("--dev", action="store_true", help="Include dev dependencies")
    
    args = parser.parse_args()
    
    manager = DependencyManager(args.project_root)
    
    if args.command == "detect":
        dep_type = manager.detect_dependency_manager()
        print(f"Dependency Manager: {dep_type}")
    
    elif args.command == "lock":
        dep_type = manager.detect_dependency_manager()
        if dep_type == "poetry":
            manager.poetry_lock()
        else:
            manager.generate_pip_lock_file()
    
    elif args.command == "install":
        manager.install_from_lock()
    
    elif args.command == "verify":
        manager.verify_dependencies()
    
    elif args.command == "update":
        dep_type = manager.detect_dependency_manager()
        if dep_type == "poetry":
            manager.poetry_lock(update=True)
        else:
            manager.update_pip_dependencies(args.package)
            manager.generate_pip_lock_file()
    
    elif args.command == "add":
        manager.poetry_add_dependency(args.package, args.dev)
    
    elif args.command == "export":
        manager.poetry_export_requirements(args.dev)
    
    elif args.command == "outdated":
        manager.check_outdated()
    
    elif args.command == "report":
        manager.generate_dependency_report()
    
    elif args.command == "setup-script":
        manager.create_setup_script()
    
    else:
        parser.print_help()


if __name__ == "__main__":
    main()